import logging
from abc import abstractmethod, ABC
from typing import Dict, Any, List, Optional, Iterable

from geosat.cloud import PointCloud
from typing_extensions import Self

from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata

logger = logging.getLogger(__name__)


class MissingRequiredOption(Exception):
    ...


class Stage(ABC):
    """This interface defines the methods to be implemented
    by all the types that want to be used in a processing pipeline
    """

    def __init__(self, stage_name: Optional[str] = None) -> None:
        """The Stage instance must be initialisable without any arguments."""
        self.stage_name: str = stage_name or self.__class__.__name__

    @classmethod
    def from_options(cls, opts: Dict[str, Any]) -> Self:
        stage_name: Optional[str] = opts.pop("name", None)
        self = cls(stage_name=stage_name)
        self.init_from(opts)
        return self

    def init_from(self, opts_dict: Dict[str, Any]) -> None:
        stage_options: Dict[str, Option] = {
            option.name: option for option in self.options()
        }
        for opt_name in opts_dict:
            if opt_name not in stage_options:
                logger.warning(
                    f"'{self.__class__.__name__}' does not use option '{opt_name}'"
                )
        for opt in stage_options.values():
            try:
                value = opts_dict[opt.name]
                setattr(self, opt.name, opt.type(value))
            except KeyError as exception:
                if opt.required:
                    raise MissingRequiredOption(
                        f"Stage '{self.__class__.__name__}' requires option {exception}, "
                        "but it was not provided"
                    ) from exception
                # otherwise = The value should already be set in the instance don't touch it

    @abstractmethod
    def options(self) -> List[Option]:
        """
        :return: The list of option the stage supports
        """

    @abstractmethod
    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        ...
